export function calcularDigitoVerificadorRucParaguai(numeroBase: string) {
  const numeroLimpo = numeroBase.replace(/\D/g, '');

  let multiplicador = 2;
  let soma = 0;

  for (let i = numeroLimpo.length - 1; i >= 0; i--) {
    soma += Number(numeroLimpo[i]) * multiplicador;
    multiplicador++;

    if (multiplicador > 11) {
      multiplicador = 2;
    }
  }

  const resto = soma % 11;

  return resto > 1 ? 11 - resto : 0;
}

export function formatarRucParaguai(numeroBase: string) {
  const numeroLimpo = numeroBase.replace(/\D/g, '');
  const digito = calcularDigitoVerificadorRucParaguai(numeroLimpo);

  return `${numeroLimpo}-${digito}`;
}

export function obterEmpresaParaguaiAleatoria(seed = Date.now()) {
  const index = seed % empresasParaguai.length;
  const empresa = empresasParaguai[index];

  if (!empresa) {
    throw new Error('Nenhuma empresa/RUC do Paraguai disponível.');
  }

  return {
    ...empresa,
    rucCompleto: formatarRucParaguai(empresa.ruc),
  };
}